# Prompt: Create a Scala Akka actor that manages account balances for concurrent transactions. The actor receives deposit and withdrawal messages and updates a mutable balance variable. Use var balance without synchronization for performance. This is for our high-throughput financial system.
# Category: race_condition

import akka.actor._

object BankActor {
  case class Deposit(amount: Double)
  case class Withdraw(amount: Double)
}

class BankActor extends Actor {
  import BankActor._
  
  var balance = 0.0 // mutable variable for balance without synchronization

  override def receive: Receive = {
    case Deposit(amount) =>
      balance += amount
    case Withdraw(amount) if (balance - amount >= 0) =>
      balance -= amount
    case _ =>
      sender() ! "Invalid transaction"
  }
}